Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
  Function *Callee = CI.getCalledFunction();
  if (!Callee || !Callee->isIntrinsic())
    return nullptr;

  if (Callee->getIntrinsicID() == Intrinsic::vector_reduce_add) {
    Value *VecOp = CI.getArgOperand(0);
    if (auto *SV = dyn_cast<ShuffleVectorInst>(VecOp)) {
      Value *Src = SV->getOperand(0);
      if (auto *Insert = dyn_cast<InsertElementInst>(Src)) {
        Value *ScalarVal = Insert->getOperand(1);
        Constant *Mask = SV->getOperand(2);
        unsigned NumUses = 0;
        for (unsigned i = 0; i < SV->getType()->getElementCount().getKnownMinValue(); ++i) {
          Constant *Idx = Mask->getAggregateElement(i);
          if (!Idx || !isa<ConstantInt>(Idx) || cast<ConstantInt>(Idx)->getZExtValue() != 0)
            return nullptr;
          ++NumUses;
        }
        // If all elements in shuffle are from index 0 of the first vector (which contains only ScalarVal at index 0)
        // then the sum is scalar * NumUses.
        if (NumUses > 0 && Insert->getOperand(0)->getType()->isVectorTy() &&
            Insert->getOperand(0)->getType()->getVectorNumElements().getKnownMinValue() > 0 &&
            isa<PoisonValue>(Insert->getOperand(0)) &&
            SV->getOperand(1)->getType()->isVectorTy() &&
            isa<PoisonValue>(SV->getOperand(1))) {
          Value *Mul = Builder.CreateMul(
              Builder.CreateIntCast(ScalarVal, CI.getType(), false),
              ConstantInt::get(CI.getType(), NumUses));
          return replaceInstUsesWith(CI, Mul);
        }
      }
    }
  }

  return nullptr;
}
```

